'use strict';

const fs = require('fs');
const path = require('path');

/**
 * Detect the project framework and configuration.
 * @param {string} projectDir
 * @returns {{ framework, hasNextAuth, routerType, envFile, packageJson }}
 */
function detectProject(projectDir) {
  const result = {
    framework: null,
    hasNextAuth: false,
    routerType: null,   // 'app' or 'pages'
    envFile: null,       // which .env file to use
    packageJson: null,
  };

  // Read package.json
  const pkgPath = path.join(projectDir, 'package.json');
  try {
    result.packageJson = JSON.parse(fs.readFileSync(pkgPath, 'utf8'));
  } catch {
    return result;
  }

  const deps = {
    ...result.packageJson.dependencies,
    ...result.packageJson.devDependencies,
  };

  // Detect Next.js
  if (deps['next']) {
    result.framework = 'nextjs';

    // Detect router type
    if (fs.existsSync(path.join(projectDir, 'app'))) {
      result.routerType = 'app';
    } else if (fs.existsSync(path.join(projectDir, 'src', 'app'))) {
      result.routerType = 'app';
    } else if (fs.existsSync(path.join(projectDir, 'pages'))) {
      result.routerType = 'pages';
    } else {
      result.routerType = 'app'; // default to App Router for new projects
    }

    // Check for next-auth
    result.hasNextAuth = !!(deps['next-auth'] || deps['@auth/core']);
  }

  // Determine .env file
  // Next.js prefers .env.local for secrets
  if (result.framework === 'nextjs') {
    result.envFile = path.join(projectDir, '.env.local');
  } else {
    result.envFile = path.join(projectDir, '.env');
  }

  return result;
}

/**
 * Check if a NextAuth route file already exists.
 */
function hasExistingAuthRoute(projectDir, routerType) {
  if (routerType === 'app') {
    return fs.existsSync(path.join(projectDir, 'app', 'api', 'auth', '[...nextauth]', 'route.ts'))
      || fs.existsSync(path.join(projectDir, 'app', 'api', 'auth', '[...nextauth]', 'route.js'));
  }
  return fs.existsSync(path.join(projectDir, 'pages', 'api', 'auth', '[...nextauth].ts'))
    || fs.existsSync(path.join(projectDir, 'pages', 'api', 'auth', '[...nextauth].js'));
}

module.exports = { detectProject, hasExistingAuthRoute };

'use strict';

const fs = require('fs');
const path = require('path');

/**
 * Parse a .env file into an ordered list of entries.
 * Each entry is { type: 'comment'|'var'|'blank', key?, value?, raw }.
 */
function parseEnvFile(content) {
  const entries = [];
  for (const line of content.split('\n')) {
    const trimmed = line.trim();
    if (trimmed === '') {
      entries.push({ type: 'blank', raw: '' });
    } else if (trimmed.startsWith('#')) {
      entries.push({ type: 'comment', raw: line });
    } else {
      const eqIdx = line.indexOf('=');
      if (eqIdx !== -1) {
        const key = line.slice(0, eqIdx).trim();
        const value = line.slice(eqIdx + 1).trim();
        entries.push({ type: 'var', key, value, raw: line });
      } else {
        entries.push({ type: 'comment', raw: line }); // malformed — treat as comment
      }
    }
  }
  return entries;
}

/**
 * Serialize entries back to .env string.
 */
function serializeEnv(entries) {
  return entries.map(e => {
    if (e.type === 'blank') return '';
    if (e.type === 'comment') return e.raw;
    return `${e.key}=${e.value}`;
  }).join('\n');
}

/**
 * Read and parse a .env file. Returns { entries, vars } where vars is a key→value map.
 * Returns empty state if file doesn't exist.
 */
function readEnv(filePath) {
  let content = '';
  try {
    content = fs.readFileSync(filePath, 'utf8');
  } catch {
    return { entries: [], vars: {} };
  }
  const entries = parseEnvFile(content);
  const vars = {};
  for (const e of entries) {
    if (e.type === 'var') vars[e.key] = e.value;
  }
  return { entries, vars };
}

/**
 * Write entries to a .env file. Creates parent directories if needed.
 */
function writeEnv(filePath, entries) {
  const dir = path.dirname(filePath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(filePath, serializeEnv(entries) + '\n', 'utf8');
}

/**
 * Merge new variables into an existing .env file.
 * - Never overwrites existing keys that have values
 * - Adds new keys at the end with an optional section comment
 * @param {string} filePath
 * @param {Object} newVars - { KEY: value } map
 * @param {string} [sectionComment] - e.g. "# --- Google OAuth ---"
 * @returns {{ added: string[], skipped: string[] }}
 */
function mergeEnv(filePath, newVars, sectionComment) {
  const { entries, vars } = readEnv(filePath);
  const added = [];
  const skipped = [];
  const toAdd = [];

  for (const [key, value] of Object.entries(newVars)) {
    if (vars[key] && vars[key] !== '') {
      skipped.push(key);
    } else if (vars[key] === '') {
      // Key exists but empty — update in-place
      const entry = entries.find(e => e.type === 'var' && e.key === key);
      if (entry) entry.value = value;
      added.push(key);
    } else {
      toAdd.push({ key, value });
      added.push(key);
    }
  }

  if (toAdd.length > 0) {
    entries.push({ type: 'blank', raw: '' });
    if (sectionComment) {
      entries.push({ type: 'comment', raw: sectionComment });
    }
    for (const { key, value } of toAdd) {
      entries.push({ type: 'var', key, value, raw: `${key}=${value}` });
    }
  }

  writeEnv(filePath, entries);
  return { added, skipped };
}

/**
 * Remove variables from an env file by key.
 * @returns {string[]} Keys actually removed
 */
function removeEnvVars(filePath, keys) {
  const { entries } = readEnv(filePath);
  const keySet = new Set(keys);
  const removed = [];

  const filtered = entries.filter(e => {
    if (e.type === 'var' && keySet.has(e.key)) {
      removed.push(e.key);
      return false;
    }
    return true;
  });

  // Clean up consecutive blank lines
  const cleaned = [];
  for (let i = 0; i < filtered.length; i++) {
    if (filtered[i].type === 'blank' && cleaned.length > 0 && cleaned[cleaned.length - 1].type === 'blank') {
      continue;
    }
    cleaned.push(filtered[i]);
  }

  writeEnv(filePath, cleaned);
  return removed;
}

/**
 * Ensure .env and .env.local are in .gitignore.
 */
function ensureGitignore(projectDir) {
  const gitignorePath = path.join(projectDir, '.gitignore');
  let content = '';
  try { content = fs.readFileSync(gitignorePath, 'utf8'); } catch { /* no .gitignore */ }

  const lines = content.split('\n');
  const toAdd = [];

  if (!lines.some(l => l.trim() === '.env')) toAdd.push('.env');
  if (!lines.some(l => l.trim() === '.env.local')) toAdd.push('.env.local');
  if (!lines.some(l => l.trim() === '.env*.local')) toAdd.push('.env*.local');

  if (toAdd.length > 0) {
    const section = '\n# OAuth credentials — never commit\n' + toAdd.join('\n') + '\n';
    fs.writeFileSync(gitignorePath, content + section, 'utf8');
    return toAdd;
  }
  return [];
}

module.exports = { parseEnvFile, serializeEnv, readEnv, writeEnv, mergeEnv, removeEnvVars, ensureGitignore };

'use strict';

const fs = require('fs');
const path = require('path');
const { readEnv } = require('./env');
const { PROVIDERS, getProvider } = require('../providers/registry');

/**
 * Determine which providers are configured by checking .env for non-empty client IDs.
 * @param {string} envPath - Path to .env or .env.local
 * @returns {string[]} Array of provider keys that have credentials set
 */
function detectConfiguredProviders(envPath) {
  const { vars } = readEnv(envPath);
  const configured = [];

  // Check built-in providers
  for (const [key, provider] of Object.entries(PROVIDERS)) {
    const idVar = Object.keys(provider.envVars).find(v => v.endsWith('_CLIENT_ID'));
    if (idVar && vars[idVar] && vars[idVar] !== '') {
      configured.push(key);
    }
  }

  // Check for custom providers (pattern: <NAME>_CLIENT_ID + <NAME>_ISSUER)
  for (const [varName, value] of Object.entries(vars)) {
    if (varName.endsWith('_CLIENT_ID') && value) {
      const prefix = varName.replace(/_CLIENT_ID$/, '');
      const isBuiltIn = Object.values(PROVIDERS).some(p =>
        Object.keys(p.envVars).includes(varName)
      );
      if (!isBuiltIn && vars[`${prefix}_ISSUER`]) {
        configured.push(prefix.toLowerCase());
      }
    }
  }

  return configured;
}

/**
 * Generate the NextAuth [...nextauth]/route.ts file content.
 * @param {string[]} providerKeys - e.g. ['google', 'github']
 * @returns {string} TypeScript file content
 */
function generateRouteContent(providerKeys) {
  if (providerKeys.length === 0) {
    return `import NextAuth from "next-auth";

const handler = NextAuth({
  providers: [],
  // Add providers using: plugger add <provider>
});

export { handler as GET, handler as POST };
`;
  }

  const providers = providerKeys.map(k => getProvider(k));
  const imports = ['import NextAuth from "next-auth";'];
  const configs = [];

  for (const p of providers) {
    imports.push(p.nextauth.import);
    configs.push(`    ${p.nextauth.config},`);
  }

  return `${imports.join('\n')}

const handler = NextAuth({
  providers: [
${configs.join('\n')}
  ],
  pages: {
    signIn: "/login",
  },
  callbacks: {
    async session({ session, token }) {
      if (session.user) {
        (session.user as Record<string, unknown>).id = token.sub;
      }
      return session;
    },
  },
  secret: process.env.NEXTAUTH_SECRET,
});

export { handler as GET, handler as POST };
`;
}

/**
 * Write or update the NextAuth route file.
 * @param {string} projectDir - Project root
 * @param {string[]} providerKeys - Configured providers
 * @param {object} options - { routerType: 'app'|'pages' }
 * @returns {string} Path to the written file
 */
function writeNextAuthRoute(projectDir, providerKeys, options = {}) {
  const routerType = options.routerType || 'app';
  let routePath;

  if (routerType === 'app') {
    routePath = path.join(projectDir, 'app', 'api', 'auth', '[...nextauth]', 'route.ts');
  } else {
    routePath = path.join(projectDir, 'pages', 'api', 'auth', '[...nextauth].ts');
  }

  const dir = path.dirname(routePath);
  if (!fs.existsSync(dir)) {
    fs.mkdirSync(dir, { recursive: true });
  }

  const content = routerType === 'app'
    ? generateRouteContent(providerKeys)
    : generatePagesRouteContent(providerKeys);

  fs.writeFileSync(routePath, content, 'utf8');
  return routePath;
}

/**
 * Generate route content for Pages Router (pages/api/auth/[...nextauth].ts).
 */
function generatePagesRouteContent(providerKeys) {
  if (providerKeys.length === 0) {
    return `import NextAuth from "next-auth";

export default NextAuth({
  providers: [],
  // Add providers using: plugger add <provider>
});
`;
  }

  const providers = providerKeys.map(k => getProvider(k));
  const imports = ['import NextAuth from "next-auth";'];
  const configs = [];

  for (const p of providers) {
    imports.push(p.nextauth.import);
    configs.push(`    ${p.nextauth.config},`);
  }

  return `${imports.join('\n')}

export default NextAuth({
  providers: [
${configs.join('\n')}
  ],
  secret: process.env.NEXTAUTH_SECRET,
});
`;
}

module.exports = {
  detectConfiguredProviders,
  generateRouteContent,
  generatePagesRouteContent,
  writeNextAuthRoute,
};

'use strict';

const readline = require('readline');

/**
 * Ask a question and return the answer.
 * @param {string} question
 * @param {object} [options]
 * @param {boolean} [options.mask] - Mask input for secrets
 * @param {string} [options.defaultValue]
 * @returns {Promise<string>}
 */
function ask(question, options = {}) {
  return new Promise((resolve) => {
    const rl = readline.createInterface({
      input: process.stdin,
      output: process.stdout,
    });

    const prompt = options.defaultValue
      ? `${question} [${options.defaultValue}]: `
      : `${question}: `;

    rl.question(prompt, (answer) => {
      rl.close();
      resolve(answer.trim() || options.defaultValue || '');
    });
  });
}

/**
 * Ask for confirmation (y/n).
 * @param {string} question
 * @param {boolean} [defaultYes=true]
 * @returns {Promise<boolean>}
 */
function confirm(question, defaultYes = true) {
  const hint = defaultYes ? '[Y/n]' : '[y/N]';
  return new Promise((resolve) => {
    const rl = readline.createInterface({
      input: process.stdin,
      output: process.stdout,
    });

    rl.question(`${question} ${hint}: `, (answer) => {
      rl.close();
      const a = answer.trim().toLowerCase();
      if (a === '') resolve(defaultYes);
      else resolve(a === 'y' || a === 'yes');
    });
  });
}

/**
 * Ask for a selection from a list.
 * @param {string} question
 * @param {string[]} choices
 * @returns {Promise<string>}
 */
function select(question, choices) {
  return new Promise((resolve) => {
    const rl = readline.createInterface({
      input: process.stdin,
      output: process.stdout,
    });

    console.log(`\n${question}`);
    choices.forEach((c, i) => console.log(`  ${i + 1}) ${c}`));

    rl.question('\nSelect (number): ', (answer) => {
      rl.close();
      const idx = parseInt(answer, 10) - 1;
      if (idx >= 0 && idx < choices.length) {
        resolve(choices[idx]);
      } else {
        resolve(choices[0]);
      }
    });
  });
}

/**
 * Get provider credentials either from CLI flags or interactive prompts.
 * @param {object} provider - Provider definition from registry
 * @param {object} flags - CLI flags (e.g. { 'client-id': '...', 'client-secret': '...' })
 * @param {boolean} isInteractive - Whether to use interactive prompts
 * @returns {Promise<Object>} - Map of env var name → value
 */
async function getCredentials(provider, flags, isInteractive) {
  const credentials = {};

  for (const [envVar, config] of Object.entries(provider.envVars)) {
    // Map env var names to common flag names
    let flagValue = null;
    if (envVar.endsWith('_CLIENT_ID')) flagValue = flags['client-id'];
    else if (envVar.endsWith('_CLIENT_SECRET')) flagValue = flags['client-secret'];
    else if (envVar.endsWith('_ISSUER')) flagValue = flags['issuer'];

    if (flagValue) {
      credentials[envVar] = flagValue;
    } else if (isInteractive) {
      const value = await ask(`  Enter ${config.label} for ${provider.name}`);
      credentials[envVar] = value;
    } else {
      throw new Error(`Missing --${envVar.toLowerCase().replace(/_/g, '-')} for ${provider.name}`);
    }
  }

  return credentials;
}

module.exports = { ask, confirm, select, getCredentials };

function binarySearch(arr: any[], target: any) {
  let lo = 0, hi = arr.length - 1;
  while (lo <= hi) {
    const mid = (lo + hi) >>> 1;
    if (arr[mid] === target) return mid;
    if (arr[mid] < target) lo = mid + 1;
    else hi = mid - 1;
  }
  return -1;
}

function mergeSort(arr: any[]) {
  if (arr.length <= 1) return arr;
  const mid = arr.length >>> 1;
  const left = mergeSort(arr.slice(0, mid));
  const right = mergeSort(arr.slice(mid));
  const result = [];
  let i = 0, j = 0;
  while (i < left.length && j < right.length) {
    result.push(left[i] <= right[j] ? left[i++] : right[j++]);
  }
  while (i < left.length) result.push(left[i++]);
  while (j < right.length) result.push(right[j++]);
  return result;
}

function bfs(graph: any[], start: number) {
  const visited = new Set([start]);
  const queue = [start];
  const result = [];
  while (queue.length > 0) {
    const node = queue.shift();
    result.push(node);
    for (const neighbor of (graph[node] || [])) {
      if (!visited.has(neighbor)) {
        visited.add(neighbor);
        queue.push(neighbor);
      }
    }
  }
  return result;
}

class LRUCache {
  constructor(capacity) {
    this.capacity = capacity;
    this.cache = new Map();
  }
  get(key) {
    if (!this.cache.has(key)) return undefined;
    const val = this.cache.get(key);
    this.cache.delete(key);
    this.cache.set(key, val);
    return val;
  }
  set(key, val) {
    if (this.cache.has(key)) this.cache.delete(key);
    else if (this.cache.size >= this.capacity) {
      this.cache.delete(this.cache.keys().next().value);
    }
    this.cache.set(key, val);
  }
}

function validateEmail(email: any[]) {
  if (typeof email !== 'string') return false;
  const re = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return re.test(email) && email.length <= 254;
}

function computeConsensusScore(agentOutputs, weights) {
  const { coherency = 0.4, selfConfidence = 0.2, peerScore = 0.4 } = weights;
  return agentOutputs.map(output => {
    const total = (output.coherency || 0) * coherency
      + (output.confidence || 0) * selfConfidence
      + (output.peerScore || 0) * peerScore;
    return { agent: output.agent, totalScore: Math.round(total * 1000) / 1000 };
  }).sort((a, b) => b.totalScore - a.totalScore);
}

function writeGuard(newPatterns, diskPatterns) {
  if (newPatterns.length < diskPatterns.length) {
    const lost = diskPatterns.length - newPatterns.length;
    throw new Error('WRITE GUARD: refusing to save ' + newPatterns.length + ' patterns over ' + diskPatterns.length + ' — would lose ' + lost + ' patterns');
  }
  return true;
}

function acquireLock(dir, label) {
  const fs = require('fs');
  const path = require('path');
  const LOCK_DELAYS = [50, 100, 200, 400, 800];
  const STALE_LOCK_MS = 30000;
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  const lockPath = path.join(dir, '.lock');
  for (let attempt = 0; attempt <= LOCK_DELAYS.length; attempt++) {
    try {
      const fd = fs.openSync(lockPath, fs.constants.O_CREAT | fs.constants.O_EXCL | fs.constants.O_WRONLY);
      fs.writeFileSync(fd, String(process.pid), 'utf-8');
      fs.closeSync(fd);
      return () => { try { fs.unlinkSync(lockPath); } catch {} };
    } catch {
      try {
        const stat = fs.statSync(lockPath);
        if (Date.now() - stat.mtimeMs > STALE_LOCK_MS) {
          try { fs.unlinkSync(lockPath); } catch {} continue;
        }
      } catch { continue; }
      if (attempt < LOCK_DELAYS.length) {
        const buf = new Int32Array(new SharedArrayBuffer(4));
        Atomics.wait(buf, 0, 0, LOCK_DELAYS[attempt]);
      }
    }
  }
  return () => {};
}

function loadJSONWithRecovery(filePath, fallback) {
  const fs = require('fs');
  try {
    if (fs.existsSync(filePath)) {
      return JSON.parse(fs.readFileSync(filePath, 'utf-8'));
    }
  } catch {}
  const bakPath = filePath + '.bak';
  try {
    if (fs.existsSync(bakPath)) {
      const raw = fs.readFileSync(bakPath, 'utf-8');
      const parsed = JSON.parse(raw);
      try { fs.writeFileSync(filePath, raw, 'utf-8'); } catch {}
      return parsed;
    }
  } catch {}
  if (!fs.existsSync(filePath) && !fs.existsSync(bakPath)) return fallback;
  throw new Error('Both primary and backup corrupted: ' + filePath);
}

function atomicWriteJSON(filePath, data) {
  const fs = require('fs');
  const path = require('path');
  const dir = path.dirname(filePath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  const json = JSON.stringify(data, null, 2);
  const tmpPath = filePath + '.tmp';
  fs.writeFileSync(tmpPath, json, 'utf-8');
  if (fs.existsSync(filePath)) {
    try { fs.copyFileSync(filePath, filePath + '.bak'); } catch {}
  }
  fs.renameSync(tmpPath, filePath);
}

