class RequestValidator {
  constructor(schema) { this.schema = schema; }
  validate(data) {
    let errors = [];
    for (let f of Object.keys(this.schema)) { let r = this.schema[f], v = data[f];
      if (r.required && (v == null || v === '')) { errors.push(f+' is required'); continue; }
      if (v == null) continue;
      if (r.type && typeof v !== r.type) errors.push(f+' must be type '+r.type);
      if (r.min != null && v < r.min) errors.push(f+' must be >= '+r.min);
      if (r.max != null && v > r.max) errors.push(f+' must be <= '+r.max);
      if (r.pattern && !r.pattern.test(String(v))) errors.push(f+' format invalid');
      if (r.enum && !r.enum.includes(v)) errors.push(f+' must be one of: '+r.enum.join(', '));
    }
    return { valid: errors.length === 0, errors: errors };
  }
}

