class WorkerPool {
  constructor(size) { this.size = size; this.current = 0; this.active = 0; this.completed = 0; this.failed = 0; this._off = false; }
  async exec(task) {
    if (this._off) throw new Error('Pool is shut down');
    let w = this.current; this.current = (this.current + 1) % this.size; this.active++;
    try { let r = await Promise.resolve(task(w)); this.completed++; return r; }
    catch (e) { this.failed++; throw e; } finally { this.active--; }
  }
  stats() { return { size: this.size, active: this.active, completed: this.completed, failed: this.failed }; }
  shutdown() { this._off = true; }
}

