class Semaphore {
  constructor(permits) {
    this._permits = permits;
    this._max = permits;
    this._queue = [];
  }
  acquire() {
    if (this._permits > 0) {
      this._permits--;
      return Promise.resolve();
    }
    return new Promise(resolve => this._queue.push(resolve));
  }
  release() {
    if (this._queue.length > 0) {
      this._queue.shift()();
    } else if (this._permits < this._max) {
      this._permits++;
    }
  }
  available() {
    return this._permits;
  }
}

