async function retryWithBackoff(fn: Function, options: Record<string, any>) {
  const { maxRetries = 3, baseDelay = 100, maxDelay = 5000, jitter = true } = options;
  let lastError;
  for (let i = 0; i <= maxRetries; i++) {
    try {
      return await fn();
    } catch (err) {
      lastError = err;
      if (i < maxRetries) {
        let delay = Math.min(baseDelay * Math.pow(2, i), maxDelay);
        if (jitter) delay *= 0.5 + Math.random() * 0.5;
        await new Promise(r => setTimeout(r, delay));
      }
    }
  }
  throw lastError;
}

