function PriorityQueue() { this.heap = []; }
PriorityQueue.prototype.enqueue = function(value, priority) {
  this.heap.push({value: value, priority: priority});
  let i = this.heap.length - 1;
  while (i > 0) {
    const p = (i-1) >>> 1;
    if (this.heap[p].priority <= this.heap[i].priority) break;
    let t = this.heap[p]; this.heap[p] = this.heap[i]; this.heap[i] = t;
    i = p;
  }
};
PriorityQueue.prototype.dequeue = function() {
  if (!this.heap.length) return;
  const top = this.heap[0], last = this.heap.pop();
  if (this.heap.length > 0) {
    this.heap[0] = last;
    let i = 0, n = this.heap.length;
    while (true) {
      let m = i, l = 2*i+1, r = 2*i+2;
      if (l < n && this.heap[l].priority < this.heap[m].priority) m = l;
      if (r < n && this.heap[r].priority < this.heap[m].priority) m = r;
      if (m === i) break;
      let t = this.heap[i]; this.heap[i] = this.heap[m]; this.heap[m] = t;
      i = m;
    }
  }
  return top.value;
};

