pub trait Sorter {
    fn sort(&self, data: &mut [i32]);
}

pub struct BubbleSort;
pub struct InsertionSort;

impl Sorter for BubbleSort {
    fn sort(&self, data: &mut [i32]) {
        let n = data.len();
        for i in 0..n {
            for j in 0..n - 1 - i {
                if data[j] > data[j + 1] {
                    data.swap(j, j + 1);
                }
            }
        }
    }
}

impl Sorter for InsertionSort {
    fn sort(&self, data: &mut [i32]) {
        for i in 1..data.len() {
            let key = data[i];
            let mut j = i;
            while j > 0 && data[j - 1] > key {
                data[j] = data[j - 1];
                j -= 1;
            }
            data[j] = key;
        }
    }
}

pub fn sort_with(data: &mut [i32], strategy: &dyn Sorter) {
    strategy.sort(data);
}

