class BloomFilter {
  constructor(size, hashCount) { this.size = size; this.hashCount = hashCount; this.bits = new Uint8Array(size); this.count = 0; }
  _hashes(item) {
    var s = String(item), idx = [];
    for (var i = 0; i < this.hashCount; i++) {
      var h = 0; for (var j = 0; j < s.length; j++) h = ((h << 5) - h + s.charCodeAt(j) * (i+1)) | 0;
      idx.push(Math.abs(h) % this.size);
    } return idx;
  }
  add(item) { var b = this.bits; this._hashes(item).forEach(function(i){b[i]=1}); this.count++; }
  mightContain(item) { var b = this.bits; return this._hashes(item).every(function(i){return b[i]===1}); }
  falsePositiveRate() {
    var s = 0; for (var i = 0; i < this.size; i++) if (this.bits[i]) s++;
    return Math.pow(s / this.size, this.hashCount);
  }
}

