class DIContainer {
  constructor() { this._reg = new Map(); this._sing = new Map(); }
  register(name, factory, opts) {
    this._reg.set(name, { factory: factory, singleton: !!(opts && opts.singleton) });
    this._sing.delete(name); return this;
  }
