    if (!this._reg.has(name)) throw new Error(name + ' not registered');
    var e = this._reg.get(name);
    if (e.singleton) { if (!this._sing.has(name)) this._sing.set(name, e.factory(this)); return this._sing.get(name); }
    return e.factory(this);
  }
  has(name) { return this._reg.has(name); }
}

