const crypto = require('crypto');
class JWTAuth {
  constructor(secret) { this.secret = secret; }
  _b(d) { return Buffer.from(d).toString('base64url'); }
  _h(i) { return crypto.createHmac('sha256', this.secret).update(i).digest('base64url'); }
  sign(payload, exp) {
    exp = exp || '1h'; const u = {h:36e5,m:6e4,s:1e3};
    const hd = this._b('{"alg":"HS256","typ":"JWT"}');
    const e = Date.now() + parseInt(exp) * (u[exp.slice(-1)] || 36e5);
    const bd = this._b(JSON.stringify(Object.assign({}, payload, {exp: e})));
    return hd + '.' + bd + '.' + this._h(hd + '.' + bd);
  }
  verify(t) {
    const p = t.split('.'); if (this._h(p[0]+'.'+p[1]) !== p[2]) throw new Error('Invalid signature');
    const d = JSON.parse(Buffer.from(p[1], 'base64url'));
    if (d.exp && Date.now() > d.exp) throw new Error('Token expired'); return d;
  }
  decode(t) { return JSON.parse(Buffer.from(t.split('.')[1], 'base64url')); }
}

