function cors(opts) {
  opts = opts || {};
  var o = { origin: opts.origin||'*', methods: opts.methods||'GET,HEAD,PUT,PATCH,POST,DELETE',
    headers: opts.headers||'', credentials: !!opts.credentials, maxAge: opts.maxAge||86400 };
  return function(req, res, next) {
    res.setHeader('Access-Control-Allow-Origin', o.origin);
    if (o.credentials) res.setHeader('Access-Control-Allow-Credentials', 'true');
    if (req.method === 'OPTIONS') {
      res.setHeader('Access-Control-Allow-Methods', o.methods);
      if (o.headers) res.setHeader('Access-Control-Allow-Headers', o.headers);
      res.setHeader('Access-Control-Max-Age', String(o.maxAge));
      res.writeHead(204); res.end(); return;
    }
    next();
  };
}

