function parseCSV(t, o) {
  o = o || {}; var d = o.delimiter || ',', h = o.headers !== false, q = o.quote || '"';
  var rows = [], row = [''], inQ = false, col = 0;
  for (var i = 0; i < t.length; i++) { var c = t[i];
    if (inQ) { if (c===q&&t[i+1]===q){row[col]+=q;i++} else if (c===q) inQ=false; else row[col]+=c; }
    else if (c===q) inQ=true; else if (c===d) row[++col]='';
    else if (c==='\n'||(c==='\r'&&t[i+1]==='\n')){if(c==='\r')i++;rows.push(row);row=[''];col=0;}
    else row[col]+=c;
  }
  if (row.length>1||row[0]!=='') rows.push(row);
  if (!h||!rows.length) return rows;
  var hd=rows[0];
  return rows.slice(1).map(function(r){var o={};hd.forEach(function(n,i){o[n]=r[i]||''});return o;});
}

