pub fn parse_and_double(s: &str) -> Result<i64, ParseIntError> {
    s.trim().parse::<i64>().map(|n| n * 2)
}

pub fn parse_sum(values: &[&str]) -> Result<i64, ParseIntError> {
    values.iter()
        .map(|s| s.trim().parse::<i64>())
        .try_fold(0i64, |acc, r| r.map(|n| acc + n))
}

