function pMap(items: any[], fn: Function, concurrency: any) {
  concurrency = concurrency || Infinity;
  let results = new Array(items.length);
  let index = 0;
  function worker() {
    let work = Promise.resolve();
    while (index < items.length) {
      work = (function(i) {
        return work.then(function() { return fn(items[i], i); })
          .then(function(r) { results[i] = r; });
      })(index++);
    }
    return work;
  }
  let workers = [];
  for (let i = 0; i < Math.min(concurrency, items.length); i++) workers.push(worker());
  return Promise.all(workers).then(function() { return results; });
}

