function searchRegistry(query, repos, options = {}) {
  const { language, limit = 10 } = options;
  const terms = query.toLowerCase().split(/\s+/).filter(Boolean);
  let filtered = [...repos];
  if (language) {
    filtered = filtered.filter(r => r.language === language);
  }
  const scored = filtered.map(repo => {
    let score = 0;
    for (const term of terms) {
      if (repo.name.toLowerCase().includes(term)) score += 3;
      if (repo.topics && repo.topics.some(t => t.includes(term))) score += 2;
      if (repo.description && repo.description.toLowerCase().includes(term)) score += 1;
    }
    return { ...repo, score };
  });
  return scored
    .filter(r => r.score > 0)
    .sort((a, b) => b.score - a.score)
    .slice(0, limit);
}

module.exports = { searchRegistry };

