class Observable {
  constructor(fn) { this._fn = fn; }
  subscribe(o) { return this._fn(typeof o==='function'?{next:o}:o); }
  static of() {
    const v = Array.prototype.slice.call(arguments);
    return new Observable(function(o) { v.forEach(function(x){o.next(x)}); if (o.complete)o.complete(); return {unsubscribe:function(){}}; });
  }
  map(fn) { let s =this; return new Observable(function(o) {
    return s.subscribe({next:function(v){o.next(fn(v))},error:function(e){if (o.error)o.error(e)},complete:function(){if (o.complete)o.complete()}});
  }); }
  filter(fn) { let s =this; return new Observable(function(o) {
    return s.subscribe({next:function(v){if (fn(v))o.next(v)},error:function(e){if (o.error)o.error(e)},complete:function(){if (o.complete)o.complete()}});
  }); }
}

