g.addNode('a').addNode('b').addNode('c').addEdge('a', 'b').addEdge('b', 'c');
if (g.hasCycle()) throw new Error('false cycle');
const order = g.topologicalSort();
if (order.indexOf('c') > order.indexOf('b')) throw new Error('topo fail');
if (order.indexOf('b') > order.indexOf('a')) throw new Error('topo fail 2');
const impact = g.getImpact('c');
if (!impact.includes('b')) throw new Error('impact fail');

