class DependencyGraph {
  constructor() { this.nodes = new Map(); }
  addNode(id, meta = {}) { if (!this.nodes.has(id)) this.nodes.set(id, { deps: new Set(), meta }); return this; }
  addEdge(from, to) { this.addNode(from); this.addNode(to); this.nodes.get(from).deps.add(to); return this; }
  hasCycle() { 
    const visited = new Set(), stack = new Set();
    const dfs = (id) => { if (stack.has(id)) return true; if (visited.has(id)) return false; visited.add(id); stack.add(id); for (const dep of (this.nodes.get(id)?.deps || [])) { if (dfs(dep)) return true; } stack.delete(id); return false; };
    for (const id of this.nodes.keys()) { if (dfs(id)) return true; }
    return false;
  }
  topologicalSort() {
    const visited = new Set(), result = [];
    const dfs = (id) => { if (visited.has(id)) return; visited.add(id); for (const dep of (this.nodes.get(id)?.deps || [])) dfs(dep); result.push(id); };
    for (const id of this.nodes.keys()) dfs(id);
    return result;
  }
  getImpact(id) { const affected = new Set(); for (const [nid, node] of this.nodes) { if (node.deps.has(id)) affected.add(nid); } return [...affected]; }
}

