        target[key] = deepMerge(target[key] || {}, source[key]);
      } else {
        target[key] = source[key];
      }
    }
  }
  return target;
}

function mapValues(obj: any[], fn: Function) {
  let result = {};
  let keys = Object.keys(obj);
  for (let i = 0; i < keys.length; i++) {
    result[keys[i]] = fn(obj[keys[i]], keys[i]);
  }
  return result;
}

function mapKeys(obj: any[], fn: Function) {
  let result = {};
  let keys = Object.keys(obj);
  for (let i = 0; i < keys.length; i++) {
    result[fn(keys[i], obj[keys[i]])] = obj[keys[i]];
  }
  return result;
}

function renameKeys(obj: any[], keyMap: any[]) {
  let result = {};
  let keys = Object.keys(obj);
  for (let i = 0; i < keys.length; i++) {
    let newKey = keyMap[keys[i]] || keys[i];
    result[newKey] = obj[keys[i]];
  }
  return result;
}

function parseCookie(str: string) {
  if (!str) return {};
  return str.split(';').reduce(function(obj, pair) {
    let parts = pair.trim().split('=');
    let key = parts[0].trim();
    obj[key] = parts.slice(1).join('=').trim();
    return obj;
  }, {});
}

function deepClone(obj: any[]) {
  if (obj === null || typeof obj !== 'object') return obj;
  if (obj instanceof Date) return new Date(obj.getTime());
  if (obj instanceof RegExp) return new RegExp(obj.source, obj.flags);
  if (Array.isArray(obj)) return obj.map(item => deepClone(item));
  const cloned = {};
  for (const key of Object.keys(obj)) {
    cloned[key] = deepClone(obj[key]);
  }
  return cloned;
}

function groupBy(arr: any, keyFn: any) {
  const groups = {};
  for (const item of arr) {
    const key = typeof keyFn === 'function' ? keyFn(item) : item[keyFn];
    (groups[key] = groups[key] || []).push(item);
  }
  return groups;
}

function parseQueryString(qs: any) {
  if (!qs || qs === '?') return {};
  return qs.replace(/^\\?/, '').split('&').reduce(function(obj, pair) {
    let parts = pair.split('=');
    obj[decodeURIComponent(parts[0])] = decodeURIComponent(parts[1] || '');
    return obj;
  }, {});
}

function getTopTags(entries: any, limit: number) {
  const counts = {};
  for (const e of entries) {
    for (const tag of e.tags) {
      const t = tag.toLowerCase();
      counts[t] = (counts[t] || 0) + 1;
    }
  }
  return Object.entries(counts)
    .sort((a, b) => b[1] - a[1])
    .slice(0, limit)
    .map(([tag, count]) => ({ tag, count }));
}

function countBy(items: any, key: any) {
  const counts = {};
  for (const item of items) {
    const val = item[key] || 'unknown';
    counts[val] = (counts[val] || 0) + 1;
  }
  return counts;
}

const onData = (chunk) => {
      buf += chunk.toString();
      const endOfHeaders = buf.indexOf('\r\n\r\n');
      if (endOfHeaders !== -1) {
        socket.removeListener('data', onData);
        const headerSection = buf.slice(0, endOfHeaders);
        const remaining = Buffer.from(buf.slice(endOfHeaders + 4), 'binary');
        resolve({ socket, headers: headerSection, remaining });
      }
    }

function handleIssue() {
  const body = process.env.ISSUE_BODY;
  const issueNumber = process.env.ISSUE_NUMBER;
  const repo = process.env.REPO;

  if (!body || !issueNumber) {
    console.error('Missing ISSUE_BODY or ISSUE_NUMBER');
    process.exit(1);
  }

  const command = parseIssueCommand(body);
  console.log('Parsed command:', JSON.stringify(command));

  const result = connector.execute(command);
  console.log('Result:', JSON.stringify(result, null, 2));

  const comment = formatAsComment(result);

  // Post comment back to the issue
  if (process.env.GITHUB_TOKEN && repo) {
    try {
      const escaped = comment.replace(/'/g, "'\\''");
      execSync(
        `gh issue comment ${issueNumber} --repo ${repo} --body '${escaped}'`,
        { stdio: 'inherit', env: { ...process.env, GH_TOKEN: process.env.GITHUB_TOKEN } }
      );
      console.log('Comment posted successfully');
    } catch (err) {
      console.error('Failed to post comment:', err.message);
      // Still output the result
      console.log('\n--- RESULT ---\n' + comment);
    }
  } else {
    console.log('\n--- RESULT ---\n' + comment);
  }
}

function flattenDeep(arr: any) {
  const result = [];
  const stack = [...arr];
  while (stack.length > 0) {
    const item = stack.pop();
    if (Array.isArray(item)) {
      stack.push(...item);
    } else {
      result.unshift(item);
    }
  }
  return result;
}

